patch:
--- a/multiplexer.v
+++ b/multiplexer.v
@@ -8,7 +8,7 @@
   output [7:0] out
 );

-  always @(sel) begin
+  always @(sel or data_a or data_b or data_c or data_d) begin
     case (sel)
       2'b00: out = data_a;
       2'b01: out = data_b;

before_code:
module multiplexer (
  input [7:0] data_a,
  input [7:0] data_b,
  input [7:0] data_c,
  input [7:0] data_d,
  input [1:0] sel,
  output [7:0] out
);

  always @(sel) begin
    case (sel)
      2'b00: out = data_a;
      2'b01: out = data_b;
      2'b10: out = data_c;
      2'b11: out = data_d;
      default: out = 8'b0;
    endcase
  end
endmodule

after_code:
module multiplexer (
  input [7:0] data_a,
  input [7:0] data_b,
  input [7:0] data_c,
  input [7:0] data_d,
  input [1:0] sel,
  output [7:0] out
);

  always @(sel or data_a or data_b or data_c or data_d) begin
    case (sel)
      2'b00: out = data_a;
      2'b01: out = data_b;
      2'b10: out = data_c;
      2'b11: out = data_d;
      default: out = 8'b0;
    endcase
  end
endmodule
